 * OKKI 全量数据抓取 — CDP 连接 + Playwright APIRequest 自动翻页
 *
 * 使用前：
 * 1. Chrome 已通过 --remote-debugging-port=9222 启动并登录 OKKI
 * 2. node scripts/scrape_cdp_full.js
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const CDP_URL = 'http://localhost:9222';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');
const PAGE_SIZE = 50;
const REQUEST_DELAY = 800;

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

async function main() {
  console.log('[Full Scraper] 连接到 Chrome ...');
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  let page = ctx.pages().find(p => p.url().includes('xiaoman'));

  if (!page) {
    page = await ctx.newPage();
    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
  }

  const currentUrl = page.url();
  console.log(`[Full Scraper] 当前页面: ${currentUrl}`);

  if (currentUrl.includes('login')) {
    console.error('[Full Scraper] 尚未登录，请先在 Chrome 中登录 OKKI 再运行此脚本。');
    process.exit(1);
  }

  // 方式1：用 page.evaluate 的同步 XHR（可能更可靠）
  console.log('[Full Scraper] 方式1: 同步 XHR ...');
  const firstPage = await page.evaluate(async (pageSize) => {
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      xhr.open('POST', 'https://crm.xiaoman.cn/api/customerV3Read/companyList', true);
      xhr.setRequestHeader('Content-Type', 'application/json');
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.onerror = () => reject(new Error('XHR failed'));
      xhr.send(JSON.stringify({
        page: 1,
        pageSize,
        sort: 'create_time',
        order: 'desc',
      }));
    });
  }, PAGE_SIZE);

  console.log('[Full Scraper] XHR response:', JSON.stringify(firstPage).substring(0, 500));
  const total = firstPage.data?.total || firstPage.total || 0;
  const totalPages = Math.ceil(total / PAGE_SIZE);
  console.log(`[Full Scraper] 总数: ${total}, 每页: ${PAGE_SIZE}, 共 ${totalPages} 页`);

  if (total === 0) {
    // 尝试方式2：直接拦截页面的网络请求
    console.log('[Full Scraper] 方式1 返回 0，尝试方式2: 触发页面刷新拦截...');

    const apiPromise = new Promise((resolve) => {
      page.once('response', async (response) => {
        const url = response.url();
        if (url.includes('companyList')) {
          try {
            const body = await response.json();
            resolve(body);
          } catch (_) {
            resolve(null);
          }
        }
      });
      // 超时
      setTimeout(() => resolve(null), 10000);
    });

    // 触发页面重新加载客户列表
    await page.reload({ waitUntil: 'networkidle' });
    const result2 = await apiPromise;

    if (result2 && (result2.data?.total || result2.total)) {
      console.log('[Full Scraper] 方式2 成功，继续翻页...');

      const total2 = result2.data?.total || result2.total || 0;
      const totalPages2 = Math.ceil(total2 / PAGE_SIZE);
      const list = result2.data?.list || result2.list || [];
      console.log(`[Full Scraper] 总数: ${total2}, 第1页: ${list.length} 人`);

      // 继续翻页 2..totalPages2
      const allCustomers = [...list];
      for (let p = 2; p <= totalPages2; p++) {
        await new Promise(r => setTimeout(r, REQUEST_DELAY));
        const pageResult = await page.evaluate(async ({ pageNum, pageSize }) => {
          return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();
            xhr.open('POST', 'https://crm.xiaoman.cn/api/customerV3Read/companyList', true);
            xhr.setRequestHeader('Content-Type', 'application/json');
            xhr.withCredentials = true;
            xhr.onload = () => resolve(JSON.parse(xhr.responseText));
            xhr.onerror = () => reject(new Error('XHR failed'));
            xhr.send(JSON.stringify({ page: pageNum, pageSize, sort: 'create_time', order: 'desc' }));
          });
        }, { pageNum: p, pageSize: PAGE_SIZE });
        const pageList = pageResult.data?.list || pageResult.list || [];
        allCustomers.push(...pageList);
        console.log(`[Full Scraper] 第 ${p}/${totalPages2} 页 → 累计 ${allCustomers.length} 人`);
        if (p % 5 === 0) saveSnapshot(allCustomers, total2, p);
      }
      saveSnapshot(allCustomers, total2, totalPages2);
      console.log(`\n[Full Scraper] ✅ 全量 ${allCustomers.length} 人已保存`);
      process.exit(0);
    }

    console.error('[Full Scraper] 方式2 也失败了，请检查：');
    console.error('  1. Chrome 中是否已正常登录 OKKI？');
    console.error('  2. 是否能看到客户列表？');
    process.exit(1);
  }

  // 方式1 成功，继续翻页
  const allCustomers = [];
  const list1 = firstPage.data?.list || firstPage.list || [];
  allCustomers.push(...list1);
  console.log(`[Full Scraper] 第 1/${totalPages} 页 → 累计 ${allCustomers.length} 人`);

  for (let p = 2; p <= totalPages; p++) {
    await new Promise(r => setTimeout(r, REQUEST_DELAY));
    const pageResult = await page.evaluate(async ({ pageNum, pageSize }) => {
      return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('POST', 'https://crm.xiaoman.cn/api/customerV3Read/companyList', true);
        xhr.setRequestHeader('Content-Type', 'application/json');
        xhr.withCredentials = true;
        xhr.onload = () => resolve(JSON.parse(xhr.responseText));
        xhr.onerror = () => reject(new Error('XHR failed'));
        xhr.send(JSON.stringify({ page: pageNum, pageSize, sort: 'create_time', order: 'desc' }));
      });
    }, { pageNum: p, pageSize: PAGE_SIZE });
    const pageList = pageResult.data?.list || pageResult.list || [];
    allCustomers.push(...pageList);
    console.log(`[Full Scraper] 第 ${p}/${totalPages} 页 → 累计 ${allCustomers.length} 人`);
    if (p % 5 === 0) saveSnapshot(allCustomers, total, p);
  }
  saveSnapshot(allCustomers, total, totalPages);
  console.log(`\n[Full Scraper] ✅ 全量 ${allCustomers.length} 人已保存`);
}

function saveSnapshot(customers, total, page) {
  const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const fp = path.join(OUTPUT_DIR, `okki_full_${ts}.json`);
  fs.writeFileSync(fp, JSON.stringify({
    capturedAt: ts,
    totalExpected: total,
    totalCaptured: customers.length,
    currentPage: page,
    customers,
  }, null, 2));
  console.log(`  [Save] ${fp}`);
  return ts;
}

main().catch(err => {
  console.error('[Full Scraper] 错误:', err.message);
  process.exit(1);
});
