const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 先查一个有订单的客户 company_id
  const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;
  const withOrder = customers.find(c => c.performance_order_count > 0);
  const targetId = withOrder ? withOrder.company_id : customers[0].company_id;
  const targetName = withOrder ? withOrder.name : customers[0].name;
  console.log('Target:', targetName, 'ID:', targetId);

  // 拦截所有 API 响应
  const endpoints = new Set();
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api')) return;
    const ct = resp.headers()['content-type'] || '';
    if (!ct.includes('json')) return;
    endpoints.add(resp.status() + ' ' + url.split('?')[0]);
  });

  // 导航到客户详情页
  const detailUrl = 'https://crm.xiaoman.cn/crm/customer/' + targetId;
  console.log('Navigating to:', detailUrl);
  await page.goto(detailUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });

  // 等 SPA 加载完成
  await page.waitForTimeout(5000);

  console.log('');
  console.log('===== 客户详情页调用的 API =====');
  const sorted = [...endpoints].sort();
  sorted.forEach(e => console.log('  ' + e));

  // 看看有没有聊天/邮件相关的
  const chatApis = sorted.filter(e => e.includes('chat') || e.includes('message') || e.includes('im') || e.includes('talk'));
  const mailApis = sorted.filter(e => e.includes('mail') || e.includes('email') || e.includes('edm'));
  const fileApis = sorted.filter(e => e.includes('file') || e.includes('attach') || e.includes('upload'));
  const trailApis = sorted.filter(e => e.includes('trail') || e.includes('follow') || e.includes('remark'));
  const customerApis = sorted.filter(e => e.includes('customer'));

  console.log('');
  console.log('Chat/Message APIs:', chatApis.length ? chatApis.join(', ') : 'NONE FOUND');
  console.log('Mail/Email APIs:', mailApis.length ? mailApis.join(', ') : 'NONE FOUND');
  console.log('File/Attach APIs:', fileApis.length ? fileApis.join(', ') : 'NONE FOUND');
  console.log('Trail/Follow APIs:', trailApis.length ? trailApis.join(', ') : 'NONE FOUND');
  console.log('Customer APIs:', customerApis.length ? customerApis.join('\\n  ') : 'NONE');

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
