        text: r.textContent.substring(0, 200),
        hasClick: !!r.onclick,
        classes: r.className,
        tag: r.tagName,
        childCount: r.children.length,
        firstChildTag: r.children[0]?.tagName,
      };
    }
    return { found: false };
  });
  console.log('Row info:', JSON.stringify(rowInfo, null, 2));

  // 看看有没有操作按钮
  const buttons = await page.evaluate(() => {
    const btns = [];
    document.querySelectorAll('button, a[class*=action], a[class*=detail], a[class*=view], [class*=operate]').forEach(el => {
      const text = el.textContent.trim();
      if (text.length < 30) btns.push({ tag: el.tagName, text, class: el.className });
    });
    return btns.slice(0, 30);
  });
  console.log('Buttons/links found:', JSON.stringify(buttons, null, 2));

  // 拦截 API
  const apiCalls = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api') && !url.includes('xiaoman.cn/siteapi')) return;
    const ct = resp.headers()['content-type'] || '';
    if (!ct.includes('json')) return;
    try {
      const body = await resp.json();
      apiCalls.push({ url: url.split('?')[0], status: resp.status(), dataKeys: body.data ? Object.keys(body.data).slice(0,10) : [] });
    } catch(e) {}
  });

  // 双击
  await page.locator('[class*=table] [class*=row]').first().dblclick();
  await page.waitForTimeout(5000);

  console.log('');
  console.log('APIs after double-click (' + apiCalls.length + '):');
  apiCalls.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | data=' + a.dataKeys.join(',')));
  console.log('Current URL:', page.url());

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
