const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 找所有 row-item
  const rows = await page.evaluate(() => {
    const all = document.querySelectorAll('[class*=row-item]');
    const result = [];
    all.forEach((r, i) => {
      const text = r.textContent.trim().substring(0, 150);
      const cls = r.className;
      if (text.length > 5) result.push({ index: i, class: cls, text: text });
    });
    return result.slice(0, 20);
  });
  console.log('Data rows:');
  rows.forEach(r => console.log('  [' + r.index + '] ' + r.class + '\\n      ' + r.text + '\\n'));

  // 找到包含客户名称的元素并点击
  const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;
  const target = customers[0].name;
  console.log('Looking for customer:', target);

  // 尝试直接通过文本找到包含客户名称的行
  const customerRow = await page.evaluate((targetName) => {
    const allRows = document.querySelectorAll('[class*=row-item]:not([class*=title])');
    for (const row of allRows) {
      if (row.textContent.includes(targetName)) {
        return { found: true, text: row.textContent.substring(0, 200), class: row.className };
      }
    }
    // 扩大搜索
    const allDivs = document.querySelectorAll('div');
    for (const div of allDivs) {
      if (div.textContent.trim() === targetName) {
        return { found: true, text: div.textContent, class: div.className, tag: div.tagName };
      }
    }
    return { found: false };
  }, target);
  console.log('Customer element:', JSON.stringify(customerRow, null, 2));

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
