const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));
  console.log('Current page URL:', page.url());

  // 拦截所有即将发生的 API 响应
  const apiCalls = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api') && !url.includes('xiaoman.cn/siteapi') && !url.includes('alibaba.com')) return;
    const ct = resp.headers()['content-type'] || '';
    if (!ct.includes('json')) return;
    try {
      const body = await resp.json();
      const data = body.data || {};
      apiCalls.push({
        url: url.split('?')[0],
        fullUrl: url,
        status: resp.status(),
        dataKeys: Object.keys(data).slice(0, 15),
        listLen: data.list?.length,
        recordsLen: data.records?.length,
        messagesLen: data.messages?.length,
        total: data.total || data.totalItem || data.count,
        hasList: !!data.list,
        hasRecords: !!data.records,
      });
    } catch(e) {}
  });

  // 刷新当前沟通页面，触发所有 API 重新加载
  console.log('Reloading communication page to capture all APIs...');
  await page.reload({ waitUntil: 'domcontentloaded', timeout: 30000 });
  await page.waitForTimeout(5000);

  console.log('');
  console.log('===== 沟通页面 API 调用 (' + apiCalls.length + ' 个) =====');

  // 分组显示
  const chatApis = apiCalls.filter(a => a.url.includes('chat') || a.url.includes('message') || a.url.includes('im') || a.url.includes('talk') || a.url.includes('tm'));
  const mailApis = apiCalls.filter(a => a.url.includes('mail') || a.url.includes('email') || a.url.includes('edm'));
  const trailApis = apiCalls.filter(a => a.url.includes('trail') || a.url.includes('follow') || a.url.includes('remark'));
  const customerApis = apiCalls.filter(a => a.url.includes('customer') || a.url.includes('company'));
  const otherApis = apiCalls.filter(a => !chatApis.includes(a) && !mailApis.includes(a) && !trailApis.includes(a) && !customerApis.includes(a));

  console.log('\\n💬 Chat/Message APIs:');
  chatApis.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | list=' + a.listLen + ' msgs=' + a.messagesLen + ' records=' + a.recordsLen + ' total=' + a.total + ' | keys=' + a.dataKeys.join(',')));

  console.log('\\n📧 Mail/Email APIs:');
  mailApis.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | list=' + a.listLen + ' total=' + a.total + ' | keys=' + a.dataKeys.join(',')));

  console.log('\\n📝 Trail/Follow APIs:');
  trailApis.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | list=' + a.listLen + ' total=' + a.total + ' | keys=' + a.dataKeys.join(',')));

  console.log('\\n👤 Customer APIs:');
  customerApis.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | list=' + a.listLen + ' total=' + a.total + ' | keys=' + a.dataKeys.join(',')));

  console.log('\\nOther APIs (' + otherApis.length + '):');
  otherApis.forEach(a => console.log('  ' + a.status + ' ' + a.url + ' | keys=' + a.dataKeys.join(',')));

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
