const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 拦截并深度分析关键 API
  const deepCaptures = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    // 聚焦这些关键 API
    const targets = ['contact.list.get', 'unReadList', 'ConversationHistory', 'chatRead', 'imSetting'];
    if (!targets.some(t => url.includes(t))) return;
    try {
      const body = await resp.json();
      deepCaptures.push({ url: url.split('?')[0], body: JSON.stringify(body).substring(0, 500) });
    } catch(e) {}
  });

  // 先查关键 API 返回的数据
  console.log('=== 1. alibabaRead/unReadList (阿里未读列表) ===');
  const unread = await page.evaluate(async () => {
    const xhr = new XMLHttpRequest();
    return new Promise((resolve) => {
      xhr.open('GET', 'https://crm.xiaoman.cn/api/alibabaRead/unReadList', true);
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.send();
    });
  });
  console.log(JSON.stringify(unread).substring(0, 800));

  console.log('');
  console.log('=== 2. chatRead/GetUnreadCount (聊天未读数) ===');
  const chatUnread = await page.evaluate(async () => {
    const xhr = new XMLHttpRequest();
    return new Promise((resolve) => {
      xhr.open('GET', 'https://crm.xiaoman.cn/api/chatRead/GetUnreadCount', true);
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.send();
    });
  });
  console.log(JSON.stringify(chatUnread).substring(0, 500));

  console.log('');
  console.log('=== 3. aiAgentRead/ConversationHistory (AI对话历史) ===');
  const conv = await page.evaluate(async () => {
    const xhr = new XMLHttpRequest();
    return new Promise((resolve) => {
      // 尝试 POST - 可能需要参数
      xhr.open('POST', 'https://crm.xiaoman.cn/api/aiAgentRead/ConversationHistory', true);
      xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.onerror = () => resolve({error: 'failed'});
      xhr.send('page=1&pageSize=5');
    });
  });
  console.log(JSON.stringify(conv).substring(0, 500));

  // 检查是否有 iframe
  console.log('');
  console.log('=== 4. iframe 检测 ===');
  const frames = await page.evaluate(() => {
    const iframes = document.querySelectorAll('iframe');
    return [...iframes].map(f => ({ src: f.src?.substring(0, 150), id: f.id, class: f.className }));
  });
  frames.forEach(f => console.log(JSON.stringify(f)));

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
