  // 使用 CDP Network 域来拦截所有请求（包括 iframe）
  const cdpSession = await page.context().newCDPSession(page);
  await cdpSession.send('Network.enable');

  const apiCaptures = [];
  cdpSession.on('Network.responseReceived', async (params) => {
    const url = params.response.url;
    // 关注聊天相关的 API
    if (url.includes('message/list') || url.includes('chat/history') || 
        url.includes('contact') || url.includes('msg') || url.includes('conversation') ||
        url.includes('alibaba.icbu') || url.includes('onetalk') ||
        url.includes('acs.h.alibaba')) {
      try {
        const {body, base64Encoded} = await cdpSession.send('Network.getResponseBody', {
          requestId: params.requestId
        });
        let content = base64Encoded ? Buffer.from(body, 'base64').toString('utf-8') : body;
        content = content.substring(0, 300);
        apiCaptures.push({
          url: url.split('?')[0],
          status: params.response.status,
          preview: content,
        });
      } catch(e) {
        // 某些响应可能无法获取 body
        apiCaptures.push({
          url: url.split('?')[0],
          status: params.response.status,
          preview: '(body unavailable)',
        });
      }
    }
  });

  console.log('CDP Network monitoring active.');
  console.log('请在 TM 聊天列表中点击一个客户，等待3秒...');

  // 等待用户操作
  await new Promise(r => setTimeout(r, 15000));

  console.log('');
  console.log('===== 捕获到 ' + apiCaptures.length + ' 个聊天相关 API =====');

  // 去重显示
  const seen = new Set();
  apiCaptures.forEach(a => {
    const key = a.url + a.status;
    if (!seen.has(key)) {
      seen.add(key);
      console.log('  [' + a.status + '] ' + a.url);
      console.log('    ' + a.preview.substring(0, 200));
    }
  });

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
