const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));
  const tmFrame = page.frames().find(f => f.url().includes('onetalk.alibaba.com'));

  if (!tmFrame) { console.log('No TM frame'); process.exit(1); }

  // 深度遍历 DOM 找包含客户名称的元素
  const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;
  const targetNames = customers.slice(0, 50).map(c => c.name);

  const foundCustomers = await tmFrame.evaluate((names) => {
    const found = [];
    // 遍历所有元素
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_ELEMENT);
    let node;
    while (node = walker.nextNode()) {
      const text = node.textContent?.trim() || '';
      // 检查是否包含目标客户名
      for (const name of names) {
        if (text === name || (text.length < 100 && text.includes(name))) {
          found.push({
            name: name,
            tag: node.tagName,
            class: node.className?.substring(0, 100),
            text: text.substring(0, 200),
            path: node.closest('[class*=list], [class*=contact], [class*=chat]')?.className?.substring(0, 100) || 'no-list-parent',
          });
        }
      }
      if (found.length >= 20) break;
    }
    return found;
  }, targetNames);

  console.log('Found customer names in DOM:', foundCustomers.length);
  foundCustomers.slice(0, 20).forEach(f => console.log(JSON.stringify(f)));

  // 看看影子 DOM
  const shadowInfo = await tmFrame.evaluate(() => {
    const info = [];
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_ELEMENT);
    let node;
    while (node = walker.nextNode()) {
      if (node.shadowRoot) {
        const rootText = node.shadowRoot.textContent?.trim().substring(0, 100) || '';
        info.push({
          tag: node.tagName,
          class: node.className?.substring(0, 80),
          shadowChildren: node.shadowRoot.children.length,
          shadowText: rootText,
        });
      }
      if (info.length >= 10) break;
    }
    return info;
  });
  console.log('');
  console.log('Shadow DOM elements:', shadowInfo.length);
  shadowInfo.forEach(s => console.log(JSON.stringify(s)));

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
