const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 拦截 trailList 请求获取真实参数
  let trailParams = null;
  page.on('request', req => {
    if (req.url().includes('trailList')) {
      trailParams = { url: req.url(), method: req.method(), postData: req.postData(), headers: req.headers() };
    }
  });

  // 回到客户列表
  await page.goto('https://crm.xiaoman.cn/crm/customer/list', { waitUntil: 'domcontentloaded', timeout: 15000 });
  await page.waitForTimeout(3000);

  // 点击第一个数据行
  const clicked = await page.evaluate(() => {
    const rows = document.querySelectorAll('.row-item:not(.row-item__title)');
    if (rows.length > 0) { rows[0].click(); return true; }
    return false;
  });

  if (!clicked) { console.log('No rows to click'); process.exit(1); }

  await page.waitForTimeout(4000);

  if (trailParams) {
    console.log('TrailList POST body:', trailParams.postData);
    console.log('Content-Type:', trailParams.headers['content-type']);
  } else {
    console.log('trailList not called - trying direct API with various params...');

    // 试不同参数名
    const companyId = '94260054430870';
    const paramSets = [
      'objCompanyId=' + companyId,
      'company_id=' + companyId,
      'id=' + companyId,
      'obj_company_id=' + companyId,
    ];

    for (const params of paramSets) {
      const result = await page.evaluate(async (p) => {
        const xhr = new XMLHttpRequest();
        return new Promise((resolve) => {
          xhr.open('POST', 'https://crm.xiaoman.cn/api/customerRead/trailList', false);
          xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
          xhr.withCredentials = true;
          try { xhr.send(p); resolve({ status: xhr.status, body: xhr.responseText.substring(0, 300) }); }
          catch(e) { resolve({ error: e.message }); }
        });
      }, params);
      console.log('  ' + params + ' -> ' + JSON.stringify(result));
    }
  }

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
