    await page.goto('https://crm.xiaoman.cn/talk/hub/tm', { waitUntil: 'domcontentloaded', timeout: 15000 });
    await page.waitForTimeout(8000);
  }

  // 尝试调用阿里 MTOP API 获取联系人列表
  console.log('=== 1. Contact list API ===');
  const contacts = await page.evaluate(async () => {
    try {
      // Alibaba MTOP API 需要在页面中有相应的 JS SDK
      // 尝试直接 fetch
      const res = await fetch('https://acs.h.alibaba.com/h5/mtop.alibaba.icbu.contact.list.get/1.0/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: 'data={}',
