      const text = await res.text();
      return text.substring(0, 500);
    } catch(e) {
      return 'Error: ' + e.message;
    }
  });
  console.log('Contact list:', contacts);

  // 尝试从 iframe 的 sessionStorage 或 cookie 中获取 token
  console.log('');
  console.log('=== 2. Check iframe accessible storage ===');
  const tmFrame = page.frames().find(f => f.url().includes('onetalk.alibaba.com'));
  if (tmFrame) {
    const storage = await tmFrame.evaluate(() => {
      try {
        const keys = [];
        for (let i = 0; i < sessionStorage.length; i++) {
          keys.push(sessionStorage.key(i));
        }
        return { sessionKeys: keys.slice(0, 10), localStorage: localStorage.length };
