// Phase 1: TM 聊天 API 自动侦察
// 连接到已有 Chrome CDP → 在 onetalk 页面监听网络请求 → 点击联系人 → 捕获 API

const { chromium } = require('playwright');

const CAPTURED = []; // 捕获的所有相关请求
