// 直接 attach 到 onetalk.alibaba.com iframe target

const fs = require('fs');
// Node.js 22+ 内置 WebSocket，不需要 require

const CAPTURED = [];
let msgId = 0;

function send(ws, method, params = {}) {
    const id = ++msgId;
    ws.send(JSON.stringify({ id, method, params }));
    return id;
}

function log(msg) { console.log(msg); }

// 先获取 target 列表
function httpGet(url) {
    return new Promise((resolve, reject) => {
        const http = require(url.startsWith('https') ? 'https' : 'http');
        http.get(url, (res) => {
            let data = '';
            res.on('data', c => data += c);
            res.on('end', () => resolve(data));
        }).on('error', reject);
    });
}

(async () => {
    // 1. 获取所有 CDP targets
    const targetsJson = await httpGet('http://localhost:9222/json');
    const targets = JSON.parse(targetsJson);

    log(`📋 共 ${targets.length} 个 targets:`);
    for (const t of targets) {
        log(`  [${t.type}] ${t.title?.substring(0, 60) || '(no title)'}`);
        if (t.type === 'iframe') {
            log(`    URL: ${t.url?.substring(0, 150)}`);
            log(`    DevTools: ${t.webSocketDebuggerUrl?.substring(0, 80)}`);
        }
    }

    // 找 onetalk iframe
    const onetalk = targets.find(t =>
        t.type === 'iframe' && t.url && t.url.includes('onetalk.alibaba.com')
    );

    if (!onetalk) {
        log('\n❌ 找不到 onetalk iframe');
        process.exit(1);
    }

    log(`\n📍 目标: ${onetalk.id}`);
    log(`   WebSocket: ${onetalk.webSocketDebuggerUrl}\n`);

    // 2. 连接 WebSocket
    const ws = new WebSocket(onetalk.webSocketDebuggerUrl);

    const pendingResponses = new Map();
    const events = [];

    ws.on('message', (data) => {
        const msg = JSON.parse(data.toString());
        if (msg.id && pendingResponses.has(msg.id)) {
            pendingResponses.get(msg.id)(msg.result);
            pendingResponses.delete(msg.id);
        }
        // 收集事件
        if (msg.method) {
            events.push(msg);
        }
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = send(ws, method, params);
            pendingResponses.set(id, resolve);
        });
    }

    await new Promise((resolve) => ws.on('open', resolve));
    log('✅ WebSocket 已连接\n');

    // 3. 启用 domains
    await cmd('Network.enable');
    await cmd('Runtime.enable');
    await cmd('Page.enable');
    await cmd('DOM.enable');
    log('✅ Domains 已启用\n');

    // 4. 用 Runtime.evaluate 探测页面
    log('=== 页面探测 ===\n');

    const probeResult = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify({
                url: location.href,
                title: document.title,
                readyState: document.readyState,
                bodyChildCount: document.body ? document.body.children.length : 0,
                allElementCount: document.querySelectorAll('*').length
            })
        `,
        returnByValue: true
    });

    log('页面基本信息:', JSON.stringify(probeResult.result?.value, null, 2));

    // 找联系人列表结构
    const structureResult = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                const result = {};

                // 找 vue-recycle-scroller
                const vrs = document.querySelectorAll('.vue-recycle-scroller, [class*="recycle"]');
                result.recycleScrollers = [];
                for (const el of vrs) {
                    result.recycleScrollers.push({
                        tag: el.tagName,
                        class: (el.className?.baseVal || el.className || '').toString().substring(0, 80),
                        childCount: el.children.length,
                        firstChildClass: el.children[0]?.className?.baseVal || el.children[0]?.className || '',
                        firstChildText: el.children[0]?.textContent?.trim().substring(0, 60) || ''
                    });
                }

                // 找 ul 列表
                const uls = document.querySelectorAll('ul');
                result.ulLists = [];
                for (const ul of uls) {
                    const lis = ul.querySelectorAll(':scope > li');
                    if (lis.length >= 2) {
                        const texts = [];
                        for (let i = 0; i < Math.min(5, lis.length); i++) {
                            texts.push(lis[i].textContent?.trim().substring(0, 50) || '');
                        }
                        result.ulLists.push({
                            liCount: lis.length,
                            sampleTexts: texts,
                            ulClass: ul.className?.baseVal || ul.className || ''
                        });
                    }
                }

                // 找任何有 click 事件或 role 的列表元素
                const listItems = document.querySelectorAll('[role="listitem"], [role="option"], [class*="list-item"], [class*="chat-item"], [class*="session"], [class*="contact-item"]');
                result.listItems = listItems.length;
                if (listItems.length > 0) {
                    result.firstListItem = {
                        tag: listItems[0].tagName,
                        class: (listItems[0].className?.baseVal || listItems[0].className || '').toString().substring(0, 80),
                        text: listItems[0].textContent?.trim().substring(0, 60)
                    };
                }

                // 找所有 div 作为候选（限制数量）
                const divs = document.querySelectorAll('div[class]');
                let contentDivs = 0;
                for (const div of divs) {
                    const cls = (div.className?.baseVal || div.className || '').toString().toLowerCase();
                    if (cls.includes('contact') || cls.includes('chat') || cls.includes('session') || cls.includes('conversation')) {
                        contentDivs++;
                    }
                }
                result.contentDivCount = contentDivs;

                return result;
            })())
        `,
        returnByValue: true
    });

    const structure = JSON.parse(structureResult.result?.value || '{}');
    log('结构探测:', JSON.stringify(structure, null, 2));

    // 5. 尝试点击第一个联系人
    log('\n=== 点击联系人 ===\n');

    const clickResult = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                // 策略1: recycle scroller item
                let items = document.querySelectorAll('.vue-recycle-scroller__item-view, [class*="recycle"] [class*="item"]');
                if (items.length > 0) {
                    for (const item of items) {
                        const t = item.textContent?.trim() || '';
                        if (t.length > 1) {
                            item.click();
                            return 'clicked recycle item: ' + t.substring(0, 40);
                        }
                    }
                }

                // 策略2: ul > li
                const uls = document.querySelectorAll('ul');
                for (const ul of uls) {
                    const lis = ul.querySelectorAll(':scope > li');
                    for (const li of lis) {
                        const t = li.textContent?.trim() || '';
                        if (t.length > 2 && t.length < 100 && li.offsetHeight > 15) {
                            li.click();
                            return 'clicked ul>li: ' + t.substring(0, 40);
                        }
                    }
                }

                // 策略3: div with meaningful content
                const divs = document.querySelectorAll('div');
                for (const div of divs) {
                    const t = div.textContent?.trim() || '';
                    if (t.length > 3 && t.length < 100 && div.children.length === 0 && div.offsetHeight > 20 && div.offsetHeight < 100) {
                        div.click();
                        return 'clicked div: ' + t.substring(0, 40);
                    }
                }

                return 'FAILED: no clickable element found';
            })()
        `,
        returnByValue: true
    });

    log('点击结果:', clickResult.result?.value);

    // 6. 等待网络请求
    log('\n⏳ 等待 10 秒收集网络请求...');
    await new Promise(r => setTimeout(r, 10000));

    // 7. 分析事件
    log('\n' + '='.repeat(70));
    log('📊 网络事件分析');
    log('='.repeat(70));

    const networkReqs = events.filter(e =>
        e.method === 'Network.requestWillBeSent' ||
        e.method === 'Network.responseReceived'
    );

    log(`\n共 ${networkReqs.length} 个网络事件\n`);

    // 分类
    const reqsByType = {};
    for (const evt of events) {
        if (evt.method === 'Network.requestWillBeSent') {
            const url = evt.params.request.url;
            let category = 'other';
            if (url.includes('mtop')) category = 'MTOP';
            else if (url.includes('acs.h.alibaba')) category = 'ACS';
            else if (url.includes('message')) category = 'MESSAGE';
            else if (url.includes('chat')) category = 'CHAT';
            else if (url.includes('contact')) category = 'CONTACT';
            else if (url.includes('history')) category = 'HISTORY';
            else if (url.includes('im.')) category = 'IM';
            else if (url.match(/\.(js|css|png|jpg|gif|svg|woff2?|ico|ttf)/)) category = 'static';

            if (!reqsByType[category]) reqsByType[category] = [];
            reqsByType[category].push({
                url: url,
                method: evt.params.request.method,
                postData: evt.params.request.postData,
                type: evt.params.type
            });
        }
    }

    // 输出非静态资源的请求
    const interesting = { ...reqsByType };
    delete interesting.static;
    delete interesting.other;

    const keys = Object.keys(interesting);
    if (keys.length > 0) {
        for (const cat of keys) {
            log(`\n--- ${cat} (${interesting[cat].length} 个) ---`);
            for (const r of interesting[cat]) {
                log(`  ${r.method} ${r.url.substring(0, 180)}`);
                if (r.postData) log(`    Payload: ${r.postData.substring(0, 300)}`);
                if (r.type) log(`    Type: ${r.type}`);
            }
        }
    } else {
        log('\n❌ 没有捕获到 MTOP/消息/聊天 相关API请求');
        log('所有非静态请求:');
        const others = reqsByType.other || [];
        for (const r of others.slice(0, 20)) {
            log(`  ${r.method} ${r.url.substring(0, 180)}`);
            if (r.postData) log(`    Payload: ${r.postData.substring(0, 200)}`);
        }
    }

    // 保存
    fs.writeFileSync(
        'd:/ClaudeWorkspace/08_客户跟进/Okki/data/phase1_events.json',
        JSON.stringify({ reqsByType, allNetworkEvents: networkReqs.length }, null, 2)
    );
    log('\n💾 已保存到 data/phase1_events.json');

    ws.close();
    log('✅ 完成');
})();
