// Phase 1 v5: 加等待 + 更详细探测

const fs = require('fs');

function log(msg) { console.log(msg); }

function httpGet(url) {
    return new Promise((resolve, reject) => {
        const http = require(url.startsWith('https') ? 'https' : 'http');
        http.get(url, (res) => {
            let data = '';
            res.on('data', c => data += c);
            res.on('end', () => resolve(data));
        }).on('error', reject);
    });
}

(async () => {
    const targetsJson = await httpGet('http://localhost:9222/json');
    const targets = JSON.parse(targetsJson);

    const onetalk = targets.find(t =>
        t.type === 'iframe' && t.url && t.url.includes('onetalk.alibaba.com')
    );

    if (!onetalk) { log('找不到 onetalk'); process.exit(1); }

    log(`目标: ${onetalk.id}\n`);

    const ws = new WebSocket(onetalk.webSocketDebuggerUrl);
    const pending = new Map();
    let msgId = 0;
    const events = [];

    ws.addEventListener('message', (event) => {
        const msg = JSON.parse(event.data);
        if (msg.id && pending.has(msg.id)) {
            pending.get(msg.id)(msg.result);
            pending.delete(msg.id);
        }
        if (msg.method) events.push(msg);
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = ++msgId;
            pending.set(id, resolve);
            ws.send(JSON.stringify({ id, method, params }));
        });
    }

    await new Promise((resolve, reject) => {
        ws.addEventListener('open', resolve);
        ws.addEventListener('error', reject);
    });

    await cmd('Network.enable');
    await cmd('Runtime.enable');
    await cmd('Page.enable');
    await cmd('DOM.enable');

    log('已连接, 等页面渲染...\n');
    await new Promise(r => setTimeout(r, 3000));

    // === 探测 1: 基本信息 ===
    log('=== 页面基本信息 ===');

    const info = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                var r = {
                    url: location.href,
                    title: document.title,
                    ready: document.readyState,
                    bodyKids: document.body ? document.body.children.length : -1,
                    all: document.querySelectorAll('*').length
                };
                return JSON.stringify(r);
            })()
        `,
        returnByValue: true
    });
    log(info.result?.value || '(无)');

    // === 探测 2: 找所有有 children 的元素 ===
    log('\n=== 容器元素 ===');

    const containers = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var arr = [];
                var all = document.querySelectorAll('*');
                for (var i = 0; i < all.length; i++) {
                    var el = all[i];
                    if (el.children.length >= 3 && el.children.length <= 100) {
                        var first = el.children[0];
                        var text = (first.textContent || '').trim().substring(0, 60);
                        var cls = (el.className?.baseVal || el.className || el.getAttribute('class') || '').toString();
                        if (cls.length > 80) cls = cls.substring(0, 80);
                        arr.push({
                            tag: el.tagName,
                            cls: cls,
                            kids: el.children.length,
                            firstTag: first.tagName,
                            firstText: text
                        });
                    }
                    if (arr.length >= 30) break;
                }
                return arr;
            })())
        `,
        returnByValue: true
    });
    log(containers.result?.value || '(无)');

    // === 探测 3: 用 DOM.querySelectorAll 找特定元素 ===
    log('\n=== 元素探测 (DOM API) ===');

