// Phase 1: 使用 HTTP 版 SDK API + 重新认证

const fs = require('fs');

function httpGet(url) {
    return new Promise((resolve, reject) => {
        const http = require(url.startsWith('https') ? 'https' : 'http');
        http.get(url, (res) => {
            let data = '';
            res.on('data', c => data += c);
            res.on('end', () => resolve(data));
        }).on('error', reject);
    });
}

(async () => {
    const targetsJson = await httpGet('http://localhost:9222/json');
    const targets = JSON.parse(targetsJson);

    const onetalk = targets.find(t =>
        t.type === 'iframe' && t.url && t.url.includes('onetalk.alibaba.com')
    );
    if (!onetalk) { console.log('找不到 onetalk'); process.exit(1); }

    const ws = new WebSocket(onetalk.webSocketDebuggerUrl);
    const pending = new Map();
    let msgId = 0;

    ws.addEventListener('message', (event) => {
        const msg = JSON.parse(event.data);
        if (msg.id && pending.has(msg.id)) {
            pending.get(msg.id)(msg.result);
            pending.delete(msg.id);
        }
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = ++msgId;
            pending.set(id, resolve);
            ws.send(JSON.stringify({ id, method, params }));
        });
    }

    await new Promise((resolve, reject) => {
        ws.addEventListener('open', resolve);
        ws.addEventListener('error', reject);
    });

    await cmd('Runtime.enable');

    // === 1. 探索 getMessageServiceHttp ===
    console.log('=== getMessageServiceHttp 方法 ===\n');

    const httpMsgSvc = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var baas = window._imBaaSSDK;
                if (!baas) return { error: 'no baas' };

                var httpSvc = baas.getMessageServiceHttp();
                if (!httpSvc) return { error: 'no http svc' };

                var methods = [];
                var proto = Object.getPrototypeOf(httpSvc);
                while (proto) {
                    var names = Object.getOwnPropertyNames(proto);
                    for (var i = 0; i < names.length; i++) {
                        if (typeof proto[names[i]] === 'function') {
                            methods.push(names[i] + '(' + proto[names[i]].length + ')');
                        }
                    }
                    proto = Object.getPrototypeOf(proto);
                }
                return { methods: methods };
            })())
        `,
        returnByValue: true
    });
    console.log(httpMsgSvc.result?.value || '(无)');

    // === 2. 探索 getConversationServiceHttp ===
    console.log('\n=== getConversationServiceHttp 方法 ===\n');

    const httpConvSvc = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var baas = window._imBaaSSDK;
                var httpSvc = baas.getConversationServiceHttp();
                if (!httpSvc) return { error: 'no http svc' };

                var methods = [];
