                    for (var i = 0; i < names.length; i++) {
                        if (typeof proto[names[i]] === 'function') {
                            methods.push(names[i] + '(' + proto[names[i]].length + ')');
                        }
                    }
                    proto = Object.getPrototypeOf(proto);
                }
                return { methods: methods };
            })())
        `,
        returnByValue: true
    });
    console.log(httpConvSvc.result?.value || '(无)');

    // === 3. 看 getMessageServiceV2 ===
    console.log('\n=== getMessageServiceV2 方法 ===\n');

    const msgV2 = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var baas = window._imBaaSSDK;
                var v2 = baas.getMessageServiceV2();
                if (!v2) return { error: 'no v2' };

                var methods = [];
                var proto = Object.getPrototypeOf(v2);
                while (proto) {
                    var names = Object.getOwnPropertyNames(proto);
                    for (var i = 0; i < names.length; i++) {
                        if (typeof proto[names[i]] === 'function') {
                            methods.push(names[i] + '(' + proto[names[i]].length + ')');
                        }
                    }
                    proto = Object.getPrototypeOf(proto);
                }
                return { methods: methods };
            })())
        `,
        returnByValue: true
    });
    console.log(msgV2.result?.value || '(无)');

    // === 4. 尝试重新认证 ===
    console.log('\n=== 尝试认证 ===\n');

    const auth = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                return new Promise(function(resolve) {
                    var authSvc = window._imsdk.getAuthService();

                    // 看有没有缓存的 token
                    var token = localStorage.getItem('im_token') ||
                                sessionStorage.getItem('im_token') ||
                                '';

                    // 尝试 initFromAccessToken
                    try {
                        // 先看 auth 当前状态
                        var status = {
                            isLogin: authSvc.isLogin(),
                            nick: authSvc.getLoginNick(),
                            uid: authSvc.getLoginUid(),
                            localStorageKeys: Object.keys(localStorage).filter(function(k) {
                                return k.toLowerCase().includes('token') || k.toLowerCase().includes('auth') || k.toLowerCase().includes('login');
                            })
                        };

                        // 尝试获取 openId
                        try {
                            var openId = authSvc.getOpenId({});
                            status.openIdResult = openId;
                        } catch(e) {
                            status.openIdError = e.message || String(e);
                        }

                        resolve(JSON.stringify(status));
                    } catch(e) {
                        resolve(JSON.stringify({ error: e.message || String(e) }));
                    }
                });
            })()
        `,
        awaitPromise: true,
        returnByValue: true
    });
    console.log(auth.result?.value || '(无)');

    // === 5. 用 HTTP API 直接调用 MTOP ===
    console.log('\n=== 尝试 HTTP 直接调 MTOP 消息 API ===\n');

    const mtoptest = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                return new Promise(function(resolve) {
                    // 从第一个会话获取 chatToken
                    var conv = window.__conversationListFullData__[0];
                    var chatToken = conv.chatToken;
                    var cid = conv.cid;

                    // 尝试用 MTOP HTTP API 获取消息
                    var params = {
                        conversationCode: cid,
                        count: 5
                    };

                    // 直接用 XHR 调 MTOP
                    var xhr = new XMLHttpRequest();
                    var url = 'https://acs.h.alibaba.com/h5/mtop.alibaba.icbu.im.listprevmsgs/1.0/' +
                              '?jsv=2.7.2&appKey=24889839&t=' + Date.now() +
                              '&api=mtop.alibaba.icbu.im.listPrevMsgs&v=1.0&dataType=json&type=originaljson' +
                              '&data=' + encodeURIComponent(JSON.stringify(params));

                    xhr.open('GET', url, true);
                    xhr.withCredentials = true;
                    xhr.onload = function() {
                        resolve(JSON.stringify({
                            status: xhr.status,
                            url: url.substring(0, 100),
                            body: xhr.responseText.substring(0, 1000)
                        }));
                    };
                    xhr.onerror = function() {
                        resolve(JSON.stringify({ error: 'XHR failed', status: xhr.status }));
                    };
                    xhr.send();
                });
            })()
        `,
        awaitPromise: true,
        returnByValue: true
    });
    console.log(mtoptest.result?.value || '(无)');

    ws.close();
    console.log('\n完成');
})();

