// 测试 /message/imhistory.htm

const fs = require('fs');

function httpGet(url) {
    return new Promise((resolve, reject) => {
        const http = require(url.startsWith('https') ? 'https' : 'http');
        http.get(url, (res) => {
            let data = '';
            res.on('data', c => data += c);
            res.on('end', () => resolve(data));
        }).on('error', reject);
    });
}

(async () => {
    const targetsJson = await httpGet('http://localhost:9222/json');
    const targets = JSON.parse(targetsJson);

    const onetalk = targets.find(t =>
        t.type === 'iframe' && t.url && t.url.includes('onetalk.alibaba.com')
    );
    if (!onetalk) { console.log('找不到 onetalk'); process.exit(1); }

    const ws = new WebSocket(onetalk.webSocketDebuggerUrl);
    const pending = new Map();
    let msgId = 0;

    ws.addEventListener('message', (event) => {
        const msg = JSON.parse(event.data);
        if (msg.id && pending.has(msg.id)) {
            pending.get(msg.id)(msg.result);
            pending.delete(msg.id);
        }
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = ++msgId;
            pending.set(id, resolve);
            ws.send(JSON.stringify({ id, method, params }));
        });
    }

    await new Promise((resolve, reject) => {
        ws.addEventListener('open', resolve);
        ws.addEventListener('error', reject);
    });

    await cmd('Runtime.enable');

    // === 测试 /message/imhistory.htm ===
    console.log('=== 测试 imhistory.htm ===\n');

    const conv = await cmd('Runtime.evaluate', {
        expression: 'window.__conversationListFullData__ ? window.__conversationListFullData__[0].cid : "NONE"',
        returnByValue: true
    });
    const cid = conv.result?.value;
    console.log('CID:', cid);

    // 测试不同的参数组合
    const paramSets = [
        { cid: cid, page: 1, pageSize: 10 },
        { conversationCode: cid, count: 10 },
        { conversationId: cid, pageSize: 10 },
        { conversationCode: cid, sendTime: Date.now(), count: 10 },
        { params: JSON.stringify({ conversationCode: cid, count: 10 }) }
    ];

    for (let i = 0; i < paramSets.length; i++) {
        const params = paramSets[i];
        console.log(`\n测试 ${i+1}: ${JSON.stringify(params).substring(0, 100)}`);

        const result = await cmd('Runtime.evaluate', {
            expression: `
                (function() {
                    return new Promise(function(resolve) {
                        var xhr = new XMLHttpRequest();
                        var url = 'https://onetalk.alibaba.com/message/imhistory.htm';

                        var body;
                        if (${JSON.stringify(params)}.params) {
                            body = 'params=' + encodeURIComponent(${JSON.stringify(params)}.params);
                            xhr.open('POST', url, true);
                            xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
                        } else {
                            // GET
                            var qs = Object.entries(${JSON.stringify(params)}).map(function(e) {
                                return e[0] + '=' + encodeURIComponent(e[1]);
                            }).join('&');
                            xhr.open('GET', url + '?' + qs, true);
                        }

                        xhr.withCredentials = true;
                        xhr.onload = function() {
                            var body = xhr.responseText.substring(0, 2000);
                            try {
                                var json = JSON.parse(xhr.responseText);
                                resolve(JSON.stringify({
                                    method: 'GET',
                                    status: xhr.status,
                                    keys: Object.keys(json),
                                    preview: JSON.stringify(json).substring(0, 500)
                                }));
                            } catch(e) {
                                resolve(JSON.stringify({
                                    status: xhr.status,
                                    preview: xhr.responseText.substring(0, 500)
                                }));
                            }
                        };
                        xhr.onerror = function() {
                            resolve(JSON.stringify({ error: true, status: xhr.status }));
                        };
                        xhr.send(body);
                    });
                })()
            `,
            awaitPromise: true,
            returnByValue: true
        });
        console.log(result.result?.value || '(无)');
    }

    ws.close();
    console.log('\n完成');
})();

