    const onetalk = targets.find(t =>
        t.type === 'iframe' && t.url && t.url.includes('onetalk.alibaba.com')
    );
    if (!onetalk) { console.log('找不到 onetalk'); process.exit(1); }

    const ws = new WebSocket(onetalk.webSocketDebuggerUrl);
    const pending = new Map();
    let msgId = 0;

    ws.addEventListener('message', (event) => {
        const msg = JSON.parse(event.data);
        if (msg.id && pending.has(msg.id)) {
            pending.get(msg.id)(msg.result);
            pending.delete(msg.id);
        }
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = ++msgId;
            pending.set(id, resolve);
            ws.send(JSON.stringify({ id, method, params }));
        });
    }

    await new Promise((resolve, reject) => {
        ws.addEventListener('open', resolve);
        ws.addEventListener('error', reject);
    });

    await cmd('Runtime.enable');
    await cmd('Network.enable');

    // === 1. 先用 Input.dispatchMouseEvent 模拟真实点击 ===
    console.log('=== 模拟点击 Ungroup 下第一个联系人 ===\n');

    // 找到第一个 contact-node 的位置
    const findContact = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                // 找一个 Ungroup 下的 contact-node (不是 group-node)
                var nodes = document.querySelectorAll('.im-next-tree-node.contact-node');
                if (nodes.length > 0) {
                    var first = nodes[0];
                    var rect = first.getBoundingClientRect();
                    return JSON.stringify({
                        text: first.textContent.trim(),
                        x: rect.left + rect.width / 2,
                        y: rect.top + rect.height / 2,
                        width: rect.width,
                        height: rect.height
                    });
                }

                // 如果没有 contact-node，找 contact-item-container
                var items = document.querySelectorAll('.contact-item-container');
                if (items.length > 0) {
                    // 找第一个不是 selected 的
