    console.log('\n=== 重连后拉消息 ===\n');

    const msgsFinal = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                return new Promise(function(resolve) {
                    var fullData = window.__conversationListFullData__;
                    if (!fullData || !fullData[0]) { resolve('no data'); return; }

                    // 用当前选中的会话
                    var targetCid = fullData[0].cid;
                    // 找 selected 的 contact
                    var selected = document.querySelector('.contact-item-container.selected');
