                        // 从 DOM 推断 cid 不太现实，直接用第一个
                    }

                    var msgSvc = window._imsdk.getMessageService();
                    msgSvc.listMessageWithConversationCodeForHistory({
                        conversationCode: targetCid,
                        count: 10,
                        dataCallback: function(result) {
                            var data = result.data || [];
                            resolve(JSON.stringify({
                                count: data.length,
                                hasMore: result.hasMore,
                                msgs: data.slice(0, 5).map(function(m) {
                                    return {
                                        content: (m.content||'').substring(0, 150),
                                        time: m.sendTime,
                                        sender: m.from ? m.from.name||m.from.accountId : '?'
                                    };
