                            }));
                        },
                        errorCallBack: function(err) {
                            resolve(JSON.stringify({ error: String(err&&(err.message||err.err)||'unknown') }));
                        }
                    });
                });
            })()
        `,
        awaitPromise: true,
        returnByValue: true
    });
    console.log(msgsFinal.result?.value || '(无)');

