    console.log('\n=== 点击 Keinjol Tata（已选中）===\n');

    const clickSelected = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                var selected = document.querySelector('.contact-item-container.selected');
                if (selected) {
                    // 触发一个真实的 mousedown/mouseup
                    var evt1 = new MouseEvent('mousedown', { bubbles: true, cancelable: true });
                    var evt2 = new MouseEvent('mouseup', { bubbles: true, cancelable: true });
                    var evt3 = new MouseEvent('click', { bubbles: true, cancelable: true });
                    selected.dispatchEvent(evt1);
                    selected.dispatchEvent(evt2);
                    selected.dispatchEvent(evt3);

                    return 'clicked: ' + selected.textContent.trim().substring(0, 50);
                }
                return 'no selected contact';
            })()
        `,
        returnByValue: true
    });
    console.log(clickSelected.result?.value);

