    const finalCheck = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var auth = window._imsdk.getAuthService();
                var body = document.body.textContent;
                return {
                    isLogin: auth.isLogin(),
                    nick: auth.getLoginNick(),
                    disconnectedText: body.includes('网络连接已经断开'),
                    reconnectText: body.includes('重新连接') || body.includes('重连')
                };
            })())
        `,
        returnByValue: true
    });
    console.log('\n最终状态:', finalCheck.result?.value);

    ws.close();
    console.log('\n完成');
})();
