    const pending = new Map();
    let msgId = 0;

    ws.addEventListener('message', (event) => {
        const msg = JSON.parse(event.data);
        if (msg.id && pending.has(msg.id)) {
            pending.get(msg.id)(msg.result);
            pending.delete(msg.id);
        }
    });

    function cmd(method, params = {}) {
        return new Promise((resolve) => {
            const id = ++msgId;
            pending.set(id, resolve);
            ws.send(JSON.stringify({ id, method, params }));
        });
    }

    await new Promise((resolve, reject) => {
        ws.addEventListener('open', resolve);
        ws.addEventListener('error', reject);
    });

    await cmd('Runtime.enable');

    // === 1. 检查 fetchMessages 是否存在 ===
    console.log('=== fetchMessages 存在性 ===\n');

    const checkFetch = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var baas = window._imBaaSSDK;
                if (!baas) return { error: 'no baas' };

                var httpMsg = baas.getMessageServiceHttp();
                var wsMsg = baas.getMessageService();
                var v2Msg = baas.getMessageServiceV2();

                return {
                    httpMsg_exists: !!httpMsg,
                    httpMsg_type: typeof httpMsg,
                    httpMsg_fetchMessages: typeof (httpMsg && httpMsg.fetchMessages),
                    httpMsg_methods: httpMsg ? Object.keys(httpMsg).filter(function(k) { return typeof httpMsg[k] === 'function'; }) : [],
                    wsMsg_exists: !!wsMsg,
                    wsMsg_type: typeof wsMsg,
                    v2Msg_exists: !!v2Msg
                };
            })())
        `,
        returnByValue: true
    });
    console.log(checkFetch.result?.value || '(无)');

    // === 2. 尝试手动调用 fetchMessages ===
    console.log('\n=== 手动调用 fetchMessages ===\n');

    const manualCall = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                return new Promise(function(resolve) {
                    var baas = window._imBaaSSDK;
                    var httpMsg = baas.getMessageServiceHttp();

                    // 看 fetchMessages 源码
                    var src = httpMsg.fetchMessages ? httpMsg.fetchMessages.toString() : 'NOT A FUNCTION';

                    // 尝试调用
                    try {
                        var result = httpMsg.fetchMessages({});
                        resolve(JSON.stringify({
                            source: src.substring(0, 300),
                            callResult: typeof result,
                            isPromise: result && typeof result.then === 'function'
                        }));
                    } catch(e) {
                        resolve(JSON.stringify({
                            source: src.substring(0, 300),
                            error: e.message || String(e)
                        }));
                    }
                });
            })()
        `,
        awaitPromise: true,
        returnByValue: true
    });
    console.log(manualCall.result?.value || '(无)');

    // === 3. 查找导致错误的 v(...) 函数 ===
    console.log('\n=== 搜索 webpack 中的 fetchMessages ===\n');

    const searchWebpack = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                // webpackJsonp 可能包含模块定义
                var wpPush = window.webpackJsonp && window.webpackJsonp.push;
                var result = {};

                // 搜索全局变量名
                var keys = Object.keys(window);
                var fetchKeys = keys.filter(function(k) {
                    return k.toLowerCase().includes('fetch') || k.toLowerCase().includes('message');
                });
                result.fetchKeys = fetchKeys;

                // 检查 imsdk 原型链上的 fetchMessages
                var msgSvcHttp = window._imBaaSSDK.getMessageServiceHttp();
                var protoChain = [];
                var proto = Object.getPrototypeOf(msgSvcHttp);
                var depth = 0;
                while (proto && depth < 5) {
                    var methods = Object.getOwnPropertyNames(proto).filter(function(n) {
                        return n.includes('fetch') || n.includes('Fetch') || n.includes('message');
                    });
                    protoChain.push({
                        constructor: proto.constructor ? proto.constructor.name : 'unknown',
                        fetchMethods: methods
                    });
                    proto = Object.getPrototypeOf(proto);
                    depth++;
                }
                result.protoChain = protoChain;

                return JSON.stringify(result);
            })()
        `,
        returnByValue: true
    });
    console.log(searchWebpack.result?.value || '(无)');

    // === 4. 尝试修复：用 _imsdk.getMessageService() 替代 ===
    console.log('\n=== 用 WS 版 MessageService 直接调 ===\n');

    const wsMsgCall = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                return new Promise(function(resolve) {
                    var fullData = window.__conversationListFullData__;
                    if (!fullData || !fullData[0]) { resolve('no data'); return; }

                    // 直接用 WS MessageService（listMessageWithConversationCodeForHistory）
                    var msgSvc = window._imsdk.getMessageService();

                    msgSvc.listMessageWithConversationCodeForHistory({
                        conversationCode: fullData[0].cid,
                        count: 10,
                        dataCallback: function(result) {
                            resolve(JSON.stringify({
                                success: true,
                                count: (result.data || []).length,
                                hasMore: result.hasMore,
                                first: result.data && result.data[0] ? {
                                    content: (result.data[0].content||'').substring(0, 200),
                                    time: result.data[0].sendTime,
                                    keys: Object.keys(result.data[0]).slice(0, 20)
                                } : null
                            }));
                        },
                        errorCallBack: function(err) {
                            resolve(JSON.stringify({ error: 'WS API error: ' + JSON.stringify(err).substring(0, 200) }));
                        }
                    });
                });
            })()
        `,
        awaitPromise: true,
        returnByValue: true
    });
    console.log(wsMsgCall.result?.value || '(无)');

    // === 5. 看页面控制台错误 ===
    console.log('\n=== 检查 window 错误 ===\n');

