        expression: `
            JSON.stringify((function() {
                // 检查页面控制台中可能有的错误信息
                var result = {};

                // 看连接状态 UI
                var connStatus = document.querySelector('.connection-status-container');
                result.connStatusText = connStatus ? connStatus.textContent.trim() : 'not found';

                // 看是否有错误弹窗
                var dialogs = document.querySelectorAll('[class*="dialog"], [class*="toast"], [class*="error"], [class*="notice"]');
                var dialogTexts = [];
                for (var i = 0; i < Math.min(5, dialogs.length); i++) {
                    var t = dialogs[i].textContent.trim();
                    if (t.length > 5 && t.length < 200) dialogTexts.push(t);
                }
                result.dialogTexts = dialogTexts;

                // 检查 auth 状态
                var auth = window._imsdk.getAuthService();
                result.auth = {
                    isLogin: auth.isLogin(),
                    nick: auth.getLoginNick(),
                    uid: auth.getLoginUid()
                };

                return result;
            })())
        `,
        returnByValue: true
    });
    console.log(errors.result?.value || '(无)');

    // === 6. 尝试用 localStorage/sessionStorage 中的 token 调用 HTTP API ===
    console.log('\n=== 查找可用 token ===\n');

    const tokenHunt = await cmd('Runtime.evaluate', {
        expression: `
            JSON.stringify((function() {
                var tokens = {};

                // localStorage
                for (var i = 0; i < localStorage.length; i++) {
                    var key = localStorage.key(i);
                    if (key && (key.includes('token') || key.includes('Token') || key.includes('auth') || key.includes('Auth') || key.includes('session'))) {
                        var val = localStorage.getItem(key);
                        tokens['ls:' + key] = val ? val.substring(0, 100) : 'null';
                    }
                }

                // sessionStorage
                for (var j = 0; j < sessionStorage.length; j++) {
                    var sk = sessionStorage.key(j);
                    if (sk && (sk.includes('token') || sk.includes('Token') || sk.includes('auth') || sk.includes('session'))) {
                        var sv = sessionStorage.getItem(sk);
                        tokens['ss:' + sk] = sv ? sv.substring(0, 100) : 'null';
                    }
                }

                // cookies
                var cookies = document.cookie.split(';');
                for (var k = 0; k < cookies.length; k++) {
                    var c = cookies[k].trim();
                    if (c.includes('token') || c.includes('auth') || c.includes('session') || c.includes('login')) {
                        tokens['cookie:' + c.substring(0, 30)] = c.substring(0, 100);
                    }
                }

                return tokens;
            })())
        `,
        returnByValue: true
    });
    console.log(tokenHunt.result?.value || '(无)');

    // === 7. 检查 onetalk 页面接收的 postMessage ===
    console.log('\n=== postMessage 监听 ===\n');

    const postMsg = await cmd('Runtime.evaluate', {
        expression: `
            (function() {
                // 设置 postMessage 监听器（只能捕获之后的消息）
                window.__postMessages = [];
                window.addEventListener('message', function(e) {
                    window.__postMessages.push({
                        origin: e.origin,
                        data: typeof e.data === 'string' ? e.data.substring(0, 200) : JSON.stringify(e.data).substring(0, 200)
                    });
                });

                return 'listener set';
            })()
        `,
        returnByValue: true
    });
    console.log(postMsg.result?.value);

    await new Promise(r => setTimeout(r, 3000));

    const msgs = await cmd('Runtime.evaluate', {
        expression: 'JSON.stringify(window.__postMessages || [])',
        returnByValue: true
    });
    console.log('收到的 postMessage:', msgs.result?.value);

    ws.close();
    console.log('\n完成');
})();

